parameters.jsCode:
// Normalize and merge all signal sources into a unified company list
const crunchbaseItems = $('Crunchbase — New Funding (Global)').all();
const magnittItems = $('Magnitt — MENA Funding').all();
const proxycurlItems = $('Proxycurl — New CMO Hires (MENA+EU+US)').all();
const dealroomItems = $('Dealroom — EU Funding').all();

const normalized = [];

// Process Crunchbase
for (const item of crunchbaseItems) {
  const entities = item.json?.entities || [];
  for (const entity of entities) {
    const props = entity.properties || {};
    const location = props.location_identifiers?.[0]?.value || '';
    const region = /UAE|Saudi|Egypt|Qatar|Bahrain|Kuwait|Jordan|Lebanon/.test(location) ? 'MENA' :
                   /UK|Germany|Netherlands|Sweden|France|Spain|Italy/.test(location) ? 'EU' : 'US';
    normalized.push({
      company_name: props.identifier?.value || '',
      domain: props.website_url?.replace(/https?:\/\/(www\.)?/, '').replace(/\/$/, '') || '',
      signal_type: 'funding',
      signal_source: 'Crunchbase',
      signal_date: props.last_funding_at || new Date().toISOString().split('T')[0],
      funding_stage: props.last_funding_type || '',
      employee_count: props.employee_count || '',
      region: region,
      description: props.short_description || ''
    });
  }
}

// Process Magnitt (MENA)
const magnittData = magnittItems[0]?.json?.data || [];
for (const startup of magnittData) {
  normalized.push({
    company_name: startup.name || '',
    domain: startup.website || '',
    signal_type: 'funding',
    signal_source: 'Magnitt',
    signal_date: startup.funding_date || new Date().toISOString().split('T')[0],
    funding_stage: startup.funding_stage || '',
    employee_count: startup.team_size || '',
    region: 'MENA',
    description: startup.tagline || ''
  });
}

// Process Proxycurl CMO hires
const cmoPeople = proxycurlItems[0]?.json?.results || [];
for (const person of cmoPeople) {
  normalized.push({
    company_name: person.company || '',
    domain: '',
    signal_type: 'new_cmo',
    signal_source: 'LinkedIn/Proxycurl',
    signal_date: new Date().toISOString().split('T')[0],
    decision_maker_name: person.full_name || '',
    decision_maker_title: person.job_title || '',
    decision_maker_linkedin: person.linkedin_url || '',
    employee_count: '',
    region: person.location?.includes('UAE') || person.location?.includes('Saudi') ? 'MENA' :
             person.location?.includes('UK') || person.location?.includes('Germany') ? 'EU' : 'US',
    description: `${person.full_name} just became ${person.job_title} at ${person.company}`
  });
}

// Process Dealroom EU
const euCompanies = dealroomItems[0]?.json?.items || [];
for (const company of euCompanies) {
  normalized.push({
    company_name: company.name || '',
    domain: company.website || '',
    signal_type: 'funding',
    signal_source: 'Dealroom',
    signal_date: company.updated_at?.split('T')[0] || new Date().toISOString().split('T')[0],
    funding_stage: company.last_round?.type || '',
    employee_count: company.employee_count || '',
    region: 'EU',
    description: company.tagline || ''
  });
}

// Deduplicate by company_name + signal_type
const seen = new Set();
const deduped = normalized.filter(item => {
  const key = `${item.company_name.toLowerCase()}_${item.signal_type}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return item.company_name !== '';
});

console.log(`Signal monitor: ${deduped.length} unique signals detected`);
return deduped.map(item => ({ json: item }));

